import { useState } from "react";

function MovieItem({ movie, onDelete, onSelect }) {
    const [isEditing, setIsEditing] = useState(false);
    const [editedTitle, setEditedTitle] = useState(movie.title);

    return (
        <li onClick={() => onSelect(movie)}>
            <img src={movie.poster} alt={movie.title} />

            {isEditing ? (
                <input
                    type="text"
                    value={editedTitle}
                    onChange={(e) => setEditedTitle(e.target.value)}
                />
            ) : (
                movie.title
            )}
            <button
                onClick={(e) => {
                    e.stopPropagation();
                    setIsEditing(true);
                }}
            >
                Edit
            </button>

            <button
                onClick={(e) => {
                    e.stopPropagation();
                    onDelete(movie.id);
                }}
            >
                Delete
                <li onClick={() => {
                    console.log("CLICK WORKS");
                    onSelect(movie);
                }}></li>
            </button>
        </li>
    );
}

export default MovieItem;
